        const batch = this.sdk.contractRunner.sendBatchTransaction();
        for (const av of avatars) {
            const txData = this.baseGroup.interface.encodeFunctionData('trust', [av, BigInt('0')]);
            batch.addTransaction({
                to: this.address,
                data: txData,
                value: 0n
            });
        }
